import 'package:flutter/material.dart'; import 'package:flutter_localizations/flutter_localizations.dart'; import 'core/constants/app_identity.dart'; import 'data/datasources/local_pack_datasource.dart'; import 'presentation/screens/dashboard_screen.dart'; import 'presentation/screens/map_screen.dart'; import 'presentation/screens/point_analysis_screen.dart'; import 'presentation/screens/spectral_screen.dart'; import 'presentation/screens/gpz_screen.dart'; import 'presentation/screens/logs_screen.dart'; import 'presentation/screens/settings_screen.dart';
Future<void> main() async { WidgetsFlutterBinding.ensureInitialized(); final pack=LocalPackDatasource(); await pack.load(); runApp(BouhApp(pack:pack)); }
class BouhApp extends StatelessWidget{final LocalPackDatasource pack; const BouhApp({super.key,required this.pack}); @override Widget build(BuildContext context)=>MaterialApp(title:AppIdentity.appNameAr,debugShowCheckedModeBanner:false,locale:const Locale('ar'),supportedLocales:const [Locale('ar'),Locale('en')],localizationsDelegates:const [GlobalMaterialLocalizations.delegate,GlobalCupertinoLocalizations.delegate,GlobalWidgetsLocalizations.delegate],theme:ThemeData(brightness:Brightness.dark,useMaterial3:true,scaffoldBackgroundColor:const Color(0xFF050705),colorScheme:ColorScheme.fromSeed(seedColor:const Color(0xFFD4AF37),brightness:Brightness.dark),appBarTheme:const AppBarTheme(backgroundColor:Color(0xFF07100B),centerTitle:true)),home:Directionality(textDirection:TextDirection.rtl,child:MainShell(pack:pack)));}
class MainShell extends StatefulWidget{final LocalPackDatasource pack; const MainShell({super.key,required this.pack}); @override State<MainShell> createState()=>_S();} class _S extends State<MainShell>{int index=0; @override Widget build(BuildContext context){final screens=[DashboardScreen(pack:widget.pack),MapScreen(pack:widget.pack),const PointAnalysisScreen(),const SpectralScreen(),const GpzScreen(),const LogsScreen(),const SettingsScreen()]; return Scaffold(appBar:AppBar(title:const Text('${AppIdentity.appNameAr} | ${AppIdentity.version}')),body:screens[index],bottomNavigationBar:NavigationBar(selectedIndex:index,onDestinationSelected:(i)=>setState(()=>index=i),destinations:const [NavigationDestination(icon:Icon(Icons.dashboard),label:'الرئيسية'),NavigationDestination(icon:Icon(Icons.map),label:'الخريطة'),NavigationDestination(icon:Icon(Icons.place),label:'نقطة'),NavigationDestination(icon:Icon(Icons.science),label:'باندات'),NavigationDestination(icon:Icon(Icons.tune),label:'GPZ'),NavigationDestination(icon:Icon(Icons.list_alt),label:'السجل'),NavigationDestination(icon:Icon(Icons.settings),label:'إعدادات') ]));}}
